package com.example.ecomsearch.repository;

import com.example.ecomsearch.model.Product;
import com.example.ecomsearch.model.SearchQueryLog;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.DocWriteResponse;
import org.elasticsearch.action.bulk.BulkRequest;
import org.elasticsearch.action.bulk.BulkResponse;
import org.elasticsearch.action.delete.DeleteRequest;
import org.elasticsearch.action.get.GetRequest;
import org.elasticsearch.action.get.GetResponse;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.index.IndexResponse;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.unit.Fuzziness;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.index.reindex.BulkByScrollResponse;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.fetch.subphase.FetchSourceContext;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.stereotype.Repository;

import java.io.IOException;
import java.math.BigDecimal;
import java.time.Instant;
import java.util.*;
import java.util.stream.Collectors;

@Repository
public class ElasticsearchProductSearchRepository implements ProductSearchRepository {

    private static final String PRODUCT_INDEX = "products";
    private static final String SEARCH_LOG_INDEX = "search_queries";

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    public ElasticsearchProductSearchRepository(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
    }

    @Override
    public void indexProduct(Product product) throws IOException {
        if (product.getId() == null || product.getId().isBlank()) {
            product.setId(UUID.randomUUID().toString());
        }
        if (product.getCreatedAt() == null) {
            product.setCreatedAt(Instant.now());
        }
        product.setUpdatedAt(Instant.now());

        IndexRequest request = new IndexRequest(PRODUCT_INDEX)
                .id(product.getId())
                .source(objectMapper.convertValue(product, Map.class));

        client.index(request, RequestOptions.DEFAULT);
    }

    @Override
    public Optional<Product> getProductById(String id) throws IOException {
        GetRequest request = new GetRequest(PRODUCT_INDEX, id);
        GetResponse response = client.get(request, RequestOptions.DEFAULT);
        if (!response.isExists()) {
            return Optional.empty();
        }
        return Optional.of(objectMapper.convertValue(response.getSource(), Product.class));
    }

    @Override
    public void deleteProduct(String id) throws IOException {
        DeleteRequest request = new DeleteRequest(PRODUCT_INDEX, id);
        client.delete(request, RequestOptions.DEFAULT);
    }

    @Override
    public List<Product> bulkIndex(List<Product> products) throws IOException {
        if (products == null || products.isEmpty()) {
            return Collections.emptyList();
        }
        BulkRequest bulkRequest = new BulkRequest();
        Instant now = Instant.now();
        for (Product product : products) {
            if (product.getId() == null || product.getId().isBlank()) {
                product.setId(UUID.randomUUID().toString());
            }
            if (product.getCreatedAt() == null) {
                product.setCreatedAt(now);
            }
            product.setUpdatedAt(now);
            bulkRequest.add(new IndexRequest(PRODUCT_INDEX).id(product.getId()).source(objectMapper.convertValue(product, Map.class)));
        }
        BulkResponse response = client.bulk(bulkRequest, RequestOptions.DEFAULT);
        if (response.hasFailures()) {
            throw new IOException(response.buildFailureMessage());
        }
        return products;
    }

    @Override
    public SearchResult search(String query, int page, int size, Map<String, Object> filters) throws IOException {
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        if (query != null && !query.isBlank()) {
            boolQuery.must(QueryBuilders.multiMatchQuery(query, "name^4", "description^2", "brand^2", "category^2", "tags^2")
                    .fuzziness(Fuzziness.AUTO));
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery());
        }

        boolQuery.filter(QueryBuilders.termQuery("active", true));

        if (filters != null) {
            Object brand = filters.get("brand");
            Object category = filters.get("category");
            Object minPrice = filters.get("minPrice");
            Object maxPrice = filters.get("maxPrice");
            Object inStock = filters.get("inStock");

            if (brand != null) boolQuery.filter(QueryBuilders.termQuery("brand.keyword", brand.toString()));
            if (category != null) boolQuery.filter(QueryBuilders.termQuery("category.keyword", category.toString()));
            if (minPrice != null || maxPrice != null) {
                if (minPrice != null && maxPrice != null) {
                    boolQuery.filter(QueryBuilders.rangeQuery("price").gte(minPrice).lte(maxPrice));
                } else if (minPrice != null) {
                    boolQuery.filter(QueryBuilders.rangeQuery("price").gte(minPrice));
                } else {
                    boolQuery.filter(QueryBuilders.rangeQuery("price").lte(maxPrice));
                }
            }
            if (inStock != null && Boolean.parseBoolean(inStock.toString())) {
                boolQuery.filter(QueryBuilders.rangeQuery("stock").gt(0));
            }
        }

        sourceBuilder.query(boolQuery);
        sourceBuilder.from(Math.max(page, 0) * Math.max(size, 1));
        sourceBuilder.size(Math.max(size, 1));
        sourceBuilder.trackTotalHits(true);
        sourceBuilder.fetchSource(new FetchSourceContext(true, new String[]{"id", "name", "description", "brand", "category", "tags", "price", "stock", "rating"}, null));

        sourceBuilder.aggregation(AggregationBuilders.terms("brands").field("brand.keyword").size(20));
        sourceBuilder.aggregation(AggregationBuilders.terms("categories").field("category.keyword").size(20));
        sourceBuilder.aggregation(AggregationBuilders.terms("tags").field("tags.keyword").size(20));

        sourceBuilder.sort("_score", SortOrder.DESC);
        sourceBuilder.sort("rating", SortOrder.DESC);

        SearchRequest searchRequest = new SearchRequest(PRODUCT_INDEX);
        searchRequest.source(sourceBuilder);

        SearchResponse response = client.search(searchRequest, RequestOptions.DEFAULT);

        List<Product> products = Arrays.stream(response.getHits().getHits())
                .map(hit -> objectMapper.convertValue(hit.getSourceAsMap(), Product.class))
                .collect(Collectors.toList());

        Map<String, Map<String, Long>> facets = new HashMap<>();
        Terms brandTerms = response.getAggregations().get("brands");
        Terms categoryTerms = response.getAggregations().get("categories");
        Terms tagTerms = response.getAggregations().get("tags");

        facets.put("brand", extractTerms(brandTerms));
        facets.put("category", extractTerms(categoryTerms));
        facets.put("tags", extractTerms(tagTerms));

        return new SearchResult(products, response.getHits().getTotalHits().value, facets);
    }

    @Override
    public void logSearchQuery(SearchQueryLog log) throws IOException {
        if (log.getId() == null || log.getId().isBlank()) {
            log.setId(UUID.randomUUID().toString());
        }
        if (log.getSearchedAt() == null) {
            log.setSearchedAt(Instant.now());
        }
        IndexRequest request = new IndexRequest(SEARCH_LOG_INDEX)
                .id(log.getId())
                .source(objectMapper.convertValue(log, Map.class));
        client.index(request, RequestOptions.DEFAULT);
    }

    private Map<String, Long> extractTerms(Terms terms) {
        Map<String, Long> result = new LinkedHashMap<>();
        if (terms == null) {
            return result;
        }
        for (Terms.Bucket bucket : terms.getBuckets()) {
            result.put(bucket.getKeyAsString(), bucket.getDocCount());
        }
        return result;
    }
}

package com.example.ecomsearch.service;

import com.example.ecomsearch.dto.ProductRequest;
import com.example.ecomsearch.dto.SearchRequest;
import com.example.ecomsearch.dto.SearchResponse;
import com.example.ecomsearch.model.Product;
import com.example.ecomsearch.model.SearchQueryLog;
import com.example.ecomsearch.repository.ProductSearchRepository;
import com.example.ecomsearch.repository.SearchResult;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.HashMap;
import java.util.List;
import java.util.UUID;
import java.util.stream.Collectors;

@Service
public class ProductSearchService {

    private final ProductSearchRepository repository;

    public ProductSearchService(ProductSearchRepository repository) {
        this.repository = repository;
    }

    public Product indexProduct(ProductRequest request) throws IOException {
        Product product = new Product();
        product.setId(UUID.randomUUID().toString());
        product.setName(request.getName());
        product.setDescription(request.getDescription());
        product.setBrand(request.getBrand());
        product.setCategory(request.getCategory());
        product.setTags(request.getTags());
        product.setPrice(request.getPrice());
        product.setStock(request.getStock());
        product.setRating(request.getRating());
        product.setActive(request.getActive() == null || request.getActive());
        product.setCreatedAt(Instant.now());
        product.setUpdatedAt(Instant.now());
        repository.indexProduct(product);
        return product;
    }

    public List<Product> bulkIndex(List<ProductRequest> requests) throws IOException {
        List<Product> products = requests.stream().map(req -> {
            Product product = new Product();
            product.setId(UUID.randomUUID().toString());
            product.setName(req.getName());
            product.setDescription(req.getDescription());
            product.setBrand(req.getBrand());
            product.setCategory(req.getCategory());
            product.setTags(req.getTags());
            product.setPrice(req.getPrice());
            product.setStock(req.getStock());
            product.setRating(req.getRating());
            product.setActive(req.getActive() == null || req.getActive());
            product.setCreatedAt(Instant.now());
            product.setUpdatedAt(Instant.now());
            return product;
        }).collect(Collectors.toList());
        return repository.bulkIndex(products);
    }

    public SearchResponse search(SearchRequest request, String userId) throws IOException {
        SearchResult result = repository.search(request.getQuery(), request.getPage(), request.getSize(), request.getFilters());
        SearchQueryLog log = new SearchQueryLog();
        log.setId(UUID.randomUUID().toString());
        log.setUserId(userId);
        log.setQuery(request.getQuery());
        log.setFilters(request.getFilters() == null ? new HashMap<>() : request.getFilters());
        log.setResultCount(result.getTotal());
        log.setSearchedAt(Instant.now());
        repository.logSearchQuery(log);

        List<SearchResponse.ProductResult> productResults = result.getProducts().stream().map(product ->
                new SearchResponse.ProductResult(
                        product.getId(),
                        product.getName(),
                        product.getDescription(),
                        product.getBrand(),
                        product.getCategory(),
                        product.getTags(),
                        product.getPrice(),
                        product.getStock(),
                        product.getRating(),
                        null
                )
        ).collect(Collectors.toList());

        return new SearchResponse(productResults, result.getTotal(), result.getFacets());
    }

    public void deleteProduct(String id) throws IOException {
        repository.deleteProduct(id);
    }

    public Product getProduct(String id) throws IOException {
        return repository.getProductById(id).orElse(null);
    }
}

package com.example.ecomsearch.controller;

import com.example.ecomsearch.dto.ProductRequest;
import com.example.ecomsearch.dto.SearchRequest;
import com.example.ecomsearch.dto.SearchResponse;
import com.example.ecomsearch.model.Product;
import com.example.ecomsearch.service.ProductSearchService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.List;

@RestController
@RequestMapping("/api/search")
public class ProductSearchController {

    private final ProductSearchService service;

    public ProductSearchController(ProductSearchService service) {
        this.service = service;
    }

    @PostMapping("/product")
    public ResponseEntity<Product> indexProduct(@RequestBody ProductRequest request) throws IOException {
        return ResponseEntity.ok(service.indexProduct(request));
    }

    @PostMapping("/products/bulk")
    public ResponseEntity<List<Product>> bulkIndex(@RequestBody List<ProductRequest> requests) throws IOException {
        return ResponseEntity.ok(service.bulkIndex(requests));
    }

    @PostMapping
    public ResponseEntity<SearchResponse> search(@RequestBody SearchRequest request, @RequestHeader(value = "X-User-Id", required = false) String userId) throws IOException {
        return ResponseEntity.ok(service.search(request, userId == null ? "anonymous" : userId));
    }

    @GetMapping("/product/{id}")
    public ResponseEntity<Product> getProduct(@PathVariable String id) throws IOException {
        Product product = service.getProduct(id);
        return product == null ? ResponseEntity.notFound().build() : ResponseEntity.ok(product);
    }

    @DeleteMapping("/product/{id}")
    public ResponseEntity<Void> deleteProduct(@PathVariable String id) throws IOException {
        service.deleteProduct(id);
        return ResponseEntity.noContent().build();
    }
}

