import java.util.List;
import java.util.UUID;

@Component
public class SampleDataLoader implements CommandLineRunner {

    private final ProductSearchRepository repository;

    public SampleDataLoader(ProductSearchRepository repository) {
        this.repository = repository;
    }

    @Override
    public void run(String... args) throws Exception {
        List<Product> products = Arrays.asList(
                create("Wireless Headphones", "Noise cancelling over-ear headphones", "SoundMax", "Electronics", Arrays.asList("audio", "wireless", "headphones"), new BigDecimal("129.99"), 120, 4.7),
                create("Running Shoes", "Lightweight running shoes for men and women", "RunPro", "Sportswear", Arrays.asList("shoes", "running", "fitness"), new BigDecimal("89.99"), 65, 4.5),
                create("Coffee Maker", "Programmable drip coffee maker", "HomeBrew", "Home Appliances", Arrays.asList("coffee", "kitchen", "appliances"), new BigDecimal("59.99"), 33, 4.2)
        );
        repository.bulkIndex(products);
    }

    private Product create(String name, String description, String brand, String category, List<String> tags, BigDecimal price, Integer stock, Double rating) {
        Product p = new Product();
        p.setId(UUID.randomUUID().toString());
        p.setName(name);
        p.setDescription(description);
        p.setBrand(brand);
        p.setCategory(category);
        p.setTags(tags);
        p.setPrice(price);
        p.setStock(stock);
        p.setRating(rating);
        p.setActive(true);
        p.setCreatedAt(Instant.now());
        p.setUpdatedAt(Instant.now());
        return p;
    }
}

package com.example.ecomsearch.config;

import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.CreateIndexRequest;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.xcontent.XContentBuilder;
import org.elasticsearch.common.xcontent.XContentFactory;
import org.springframework.boot.ApplicationArguments;
import org.springframework.boot.ApplicationRunner;
import org.springframework.stereotype.Component;

import java.io.IOException;

@Component
public class ElasticsearchIndexInitializer implements ApplicationRunner {

    private final RestHighLevelClient client;

    public ElasticsearchIndexInitializer(RestHighLevelClient client) {
        this.client = client;
    }

    @Override
    public void run(ApplicationArguments args) throws Exception {
        ensureProductIndex();
        ensureSearchLogIndex();
    }

    private void ensureProductIndex() throws IOException {
        String index = "products";
        if (client.indices().exists(new GetIndexRequest(index), org.elasticsearch.client.RequestOptions.DEFAULT)) {
            return;
        }
        CreateIndexRequest request = new CreateIndexRequest(index);
        request.settings(Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 0));
        request.mapping(buildProductMapping());
        client.indices().create(request, org.elasticsearch.client.RequestOptions.DEFAULT);
    }

    private void ensureSearchLogIndex() throws IOException {
        String index = "search_queries";
        if (client.indices().exists(new GetIndexRequest(index), org.elasticsearch.client.RequestOptions.DEFAULT)) {
            return;
        }
        CreateIndexRequest request = new CreateIndexRequest(index);
        request.settings(Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 0));
        request.mapping(buildSearchLogMapping());
        client.indices().create(request, org.elasticsearch.client.RequestOptions.DEFAULT);
    }

    private XContentBuilder buildProductMapping() throws IOException {
        return XContentFactory.jsonBuilder()
                .startObject()
                .startObject("properties")
                .startObject("id").field("type", "keyword").endObject()
                .startObject("name").field("type", "text").field("analyzer", "standard")
                    .startObject("fields").startObject("keyword").field("type", "keyword").field("ignore_above", 256).endObject().endObject().endObject()
                .startObject("description").field("type", "text").endObject()
                .startObject("brand").field("type", "text")
                    .startObject("fields").startObject("keyword").field("type", "keyword").field("ignore_above", 256).endObject().endObject().endObject()
                .startObject("category").field("type", "text")
                    .startObject("fields").startObject("keyword").field("type", "keyword").field("ignore_above", 256).endObject().endObject().endObject()
                .startObject("tags").field("type", "text")
                    .startObject("fields").startObject("keyword").field("type", "keyword").field("ignore_above", 256).endObject().endObject().endObject()
                .startObject("price").field("type", "double").endObject()
                .startObject("stock").field("type", "integer").endObject()
                .startObject("rating").field("type", "double").endObject()
                .startObject("active").field("type", "boolean").endObject()
                .startObject("createdAt").field("type", "date").endObject()
                .startObject("updatedAt").field("type", "date").endObject()
                .endObject()
                .endObject();
    }

    private XContentBuilder buildSearchLogMapping() throws IOException {
        return XContentFactory.jsonBuilder()
                .startObject()
                .startObject("properties")
                .startObject("id").field("type", "keyword").endObject()
                .startObject("userId").field("type", "keyword").endObject()
                .startObject("query").field("type", "text").endObject()
                .startObject("filters").field("type", "object").endObject()
                .startObject("resultCount").field("type", "long").endObject()
                .startObject("searchedAt").field("type", "date").endObject()
                .endObject()
                .endObject();
    }
}